// Define URLs to monitor
// Add your URLs here — can also be loaded from Google Sheets or a config file
const urlsToCheck = [
  { url: 'https://yoursite.com', label: 'Homepage', critical: true },
  { url: 'https://yoursite.com/pricing', label: 'Pricing Page', critical: true },
  { url: 'https://yoursite.com/blog', label: 'Blog', critical: false },
  { url: 'https://yoursite.com/api/health', label: 'API Health Check', critical: true },
  { url: 'https://yoursite.com/contact', label: 'Contact Page', critical: false },
  { url: 'https://yoursite.com/login', label: 'Login Page', critical: true },
  { url: 'https://yoursite.com/docs', label: 'Documentation', critical: false },
  { url: 'https://app.yoursite.com', label: 'App Homepage', critical: true }
];

return urlsToCheck.map(item => ({ json: item }));

const urlData = $('Code - URL List to Check').item.json;
const response = $input.first().json;
const error = $input.first().error;

const statusCode = response.statusCode || (error ? 0 : 200);
const responseTime = response.responseTime || 0;

const isBroken = statusCode === 0 || statusCode >= 400;
const isSlow = responseTime > 3000; // >3s is slow

let statusIcon = '✅';
if (statusCode === 0) statusIcon = '💀';
else if (statusCode >= 500) statusIcon = '🔴';
else if (statusCode >= 400) statusIcon = '🟡';
else if (statusCode >= 300) statusIcon = '🟠';
else if (isSlow) statusIcon = '🐢';

return [{
  json: {
    url: urlData.url,
    label: urlData.label,
    critical: urlData.critical,
    statusCode,
    responseTime,
    isBroken,
    isSlow,
    hasIssue: isBroken || (isSlow && urlData.critical),
    statusIcon,
    errorMessage: error?.message || '',
    checkedAt: new Date().toISOString()
  }
}];
